  "pillars_popover_ideal_items": { "pt": "Menos de 3: pode limitar a variedade\n3 a 5: faixa mais equilibrada\n6 ou mais: pode dispersar a estratégia", "en": "Less than 3: may limit variety\n3 to 5: most balanced range\n6 or more: may scatter the strategy", "es": "Menos de 3: puede limitar la variedad\n3 a 5: rango más equilibrado\n6 o más: puede dispersar la estrategia" },
  "pillars_popover_ex1_title": { "pt": "Exemplo prático 1: Dentista", "en": "Practical example 1: Dentist", "es": "Ejemplo práctico 1: Dentista" },
  "pillars_popover_ex1_text": { "pt": "Para uma dentista, os pilares podem misturar estratégia e especialidades do atendimento:", "en": "For a dentist, pillars can mix strategy and service specialties:", "es": "Para una dentista, los pilares pueden mezclar estrategia y especialidades del servicio:" },
  "pillars_popover_ex1_list": { "pt": "Autoridade\nBruxismo\nInvisalign\nEstética facial\nProva social\nBastidores", "en": "Authority\nBruxism\nInvisalign\nFacial aesthetics\nSocial proof\nBehind the scenes", "es": "Autoridad\nBruxismo\nInvisalign\nEstética facial\nPrueba social\nBastidores" },
  "pillars_popover_ex1_aux": { "pt": "Para cada pilar, preencha a explicação e exemplos:", "en": "For each pillar, fill in the explanation and examples:", "es": "Para cada pilar, complete la explicación y ejemplos:" },
  "pillars_popover_ex1_example": { "pt": "Nome do pilar: Autoridade\nExplicação do pilar: Conteúdos para educar o público, responder dúvidas e reforçar credibilidade.\nExemplos de temas: Dúvidas frequentes, erros comuns, orientações, mitos e verdades.", "en": "Pillar name: Authority\nPillar explanation: Content to educate the audience, answer questions and reinforce credibility.\nExample themes: FAQs, common mistakes, guidance, myths and facts.", "es": "Nombre del pilar: Autoridad\nExplicación: Contenidos para educar al público, responder dudas y reforzar credibilidad.\nEjemplos: Preguntas frecuentes, errores comunes, orientaciones, mitos y verdades." },
  "pillars_popover_ex2_title": { "pt": "Exemplo prático 2: Nutricionista", "en": "Practical example 2: Nutritionist", "es": "Ejemplo práctico 2: Nutricionista" },
  "pillars_popover_ex2_text": { "pt": "Para uma nutricionista, os pilares podem unir educação, rotina real e conversão:", "en": "For a nutritionist, pillars can combine education, real routine and conversion:", "es": "Para una nutricionista, los pilares pueden unir educación, rutina real y conversión:" },
  "pillars_popover_ex2_list": { "pt": "Educação alimentar\nRotina real\nObjeções\nResultados\nConversão", "en": "Nutrition education\nReal routine\nObjections\nResults\nConversion", "es": "Educación alimentaria\nRutina real\nObjeciones\nResultados\nConversión" },
  "pillars_popover_ex2_aux": { "pt": "Para cada pilar, preencha a explicação e exemplos:", "en": "For each pillar, fill in the explanation and examples:", "es": "Para cada pilar, complete la explicación y ejemplos:" },
  "pillars_popover_ex2_example": { "pt": "Nome do pilar: Educação alimentar\nExplicação do pilar: Conteúdos para orientar o público sobre alimentação, hábitos e escolhas mais equilibradas.\nExemplos de temas: Lanches práticos, erros comuns, organização da rotina, mitos e estratégias simples.", "en": "Pillar name: Nutrition education\nPillar explanation: Content to guide the audience on nutrition, habits and more balanced choices.\nExample themes: Practical snacks, common mistakes, routine organization, myths and simple strategies.", "es": "Nombre: Educación alimentaria\nExplicación: Contenidos para orientar sobre alimentación, hábitos y elecciones equilibradas.\nEjemplos: Snacks prácticos, errores comunes, organización, mitos y estrategias simples." },
  "pillars_popover_ex3_title": { "pt": "Exemplo prático 3: Estúdio fitness", "en": "Practical example 3: Fitness studio", "es": "Ejemplo práctico 3: Estudio fitness" },
  "pillars_popover_ex3_text": { "pt": "Para um estúdio fitness, os pilares podem equilibrar técnica, conexão e prova de resultado:", "en": "For a fitness studio, pillars can balance technique, connection and proof of results:", "es": "Para un estudio fitness, los pilares pueden equilibrar técnica, conexión y prueba de resultados:" },
  "pillars_popover_ex3_list": { "pt": "Treino\nDor e prevenção\nBastidores\nProva social\nConversão", "en": "Training\nPain and prevention\nBehind the scenes\nSocial proof\nConversion", "es": "Entrenamiento\nDolor y prevención\nBastidores\nPrueba social\nConversión" },
  "pillars_popover_ex3_aux": { "pt": "Para cada pilar, preencha a explicação e exemplos:", "en": "For each pillar, fill in the explanation and examples:", "es": "Para cada pilar, complete la explicación y ejemplos:" },
  "pillars_popover_ex3_example": { "pt": "Nome do pilar: Treino\nExplicação do pilar: Conteúdos para mostrar exercícios, benefícios, execução e orientações práticas.\nExemplos de temas: Como executar melhor, erros frequentes, benefícios do exercício, treino para objetivos específicos.", "en": "Pillar name: Training\nPillar explanation: Content to show exercises, benefits, execution and practical guidance.\nExample themes: How to execute better, common mistakes, exercise benefits, training for specific goals.", "es": "Nombre: Entrenamiento\nExplicación: Contenidos para mostrar ejercicios, beneficios, ejecución y orientaciones prácticas.\nEjemplos: Cómo ejecutar mejor, errores frecuentes, beneficios del ejercicio, entrenamiento para objetivos." },
  "pillars_intro": { "pt": "Escolha os pilares que irão guiar a produção de conteúdo do seu cliente. Abaixo há sugestões de pilares gerais, mas você também pode criar pilares estratégicos, personalizados por serviço ou mesclá-los.", "en": "Choose the pillars that will guide your client's content production. Below are general pillar suggestions, but you can also create strategic pillars, customized by service or mix them.", "es": "Elija los pilares que guiarán la producción de contenido de su cliente. A continuación hay sugerencias generales, pero también puede crear pilares estratégicos, personalizados por servicio o combinarlos." },
  "pillars_explanation": { "pt": "São os grandes temas que orientam a produção dos posts deste cliente. Eles ajudam a manter consistência, variedade e foco estratégico no perfil.", "en": "They are the main themes that guide this client's post production. They help maintain consistency, variety and strategic focus on the profile.", "es": "Son los grandes temas que orientan la producción de posts de este cliente. Ayudan a mantener consistencia, variedad y foco estratégico en el perfil." },
