  "settings_agency_operation_mode_hint": { "pt": "Este ajuste prepara o sistema para automações futuras; não altera permissões nem o modo SOLO/equipe.", "en": "This prepares the system for future automations; it does not change permissions or SOLO/team mode.", "es": "Esto prepara el sistema para automatizaciones futuras; no cambia permisos ni el modo SOLO/equipo." },
  "settings_operation_explain_solo": { "pt": "Você faz tudo por conta própria. O sistema simplifica as etapas e assume você como responsável nas atividades.", "en": "You handle everything yourself. The system keeps steps simple and assumes you as the person responsible for activities.", "es": "Haces todo tú. El sistema simplifica los pasos y te toma como responsable de las actividades." },
  "settings_operation_explain_team": { "pt": "Você trabalha em equipe. Configure funções e níveis de acesso por colaborador, e ative múltiplas funções quando precisar de uma estrutura mais detalhada.", "en": "You work as a team. Configure functions and access levels per collaborator, and enable multiple functions when you need a more detailed setup.", "es": "Trabajas en equipo. Configura funciones y niveles de acceso por colaborador, y habilita múltiples funciones cuando necesites una estructura más detallada." },
